#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100005
#define MAXM 100005
typedef struct Edge {
    int u, v, c;
} Edge;
typedef struct Graph {
    int n, m;
    Edge *edges;
} Graph;
Graph *createGraph(int n, int m) {
    Graph *graph = (Graph *)malloc(sizeof(Graph));
    graph->n = n;
    graph->m = m;
    graph->edges = (Edge *)malloc(m * sizeof(Edge));
    return graph;
}
void addEdge(Graph *graph, int u, int v, int c) {
    graph->edges[graph->m].u = u;
    graph->edges[graph->m].v = v;
    graph->edges[graph->m].c = c;
    graph->m++;
}
int bfs(Graph *graph, int u, int v, int k) {
    int *visited = (int *)malloc(graph->n * sizeof(int));
    int *distance = (int *)malloc(graph->n * sizeof(int));
    int *attractiveness = (int *)malloc(graph->n * sizeof(int));
    for (int i = 0; i < graph->n; i++) {
        visited[i] = 0;
        distance[i] = -1;
        attractiveness[i] = 0;
    }
    visited[u] = 1;
    distance[u] = 0;
    attractiveness[u] = 0;
    int *queue = (int *)malloc(graph->n * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = u;
    while (front < rear) {
        int current = queue[front++];
        for (int i = 0; i < graph->m; i++) {
            if (graph->edges[i].u == current) {
                int neighbor = graph->edges[i].v;
                if (!visited[neighbor]) {
                    visited[neighbor] = 1;
                    distance[neighbor] = distance[current] + 1;
                    attractiveness[neighbor] = attractiveness[current] ^ (graph->edges[i].c <= k ? graph->edges[i].c : 0);
                    queue[rear++] = neighbor;
                }
            } else if (graph->edges[i].v == current) {
                int neighbor = graph->edges[i].u;
                if (!visited[neighbor]) {
                    visited[neighbor] = 1;
                    distance[neighbor] = distance[current] + 1;
                    attractiveness[neighbor] = attractiveness[current] ^ (graph->edges[i].c <= k ? graph->edges[i].c : 0);
                    queue[rear++] = neighbor;
                }
            }
        }
    }
    int result = attractiveness[v];
    free(visited);
    free(distance);
    free(attractiveness);
    free(queue);
    return result;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d", &n);
        Graph *graph = createGraph(n, 0);
        for (int i = 0; i < n - 1; i++) {
            int u, v, c;
            scanf("%d %d %d", &u, &v, &c);
            addEdge(graph, u - 1, v - 1, c);
        }
        scanf("%d", &m);
        for (int i = 0; i < m; i++) {
            int u, v, k;
            scanf("%d %d %d", &u, &v, &k);
            printf("%d\n", bfs(graph, u - 1, v - 1, k));
        }
        free(graph->edges);
        free(graph);
    }
    return 0;
}

