#include <iostream>
#include <vector>
#include <queue>
using namespace std;
const int MAXN = 100005;
typedef pair<int, int> pii;
vector<pii> adj[MAXN];
int bfs(int u, int v, int k) {
    vector<int> visited(MAXN, 0), distance(MAXN, -1), attractiveness(MAXN, 0);
    queue<int> q;
    q.push(u);
    visited[u] = 1;
    distance[u] = 0;
    attractiveness[u] = 0;
    while (!q.empty()) {
        int current = q.front();
        q.pop();
        for (auto &edge : adj[current]) {
            int neighbor = edge.first;
            if (!visited[neighbor]) {
                visited[neighbor] = 1;
                distance[neighbor] = distance[current] + 1;
                attractiveness[neighbor] = attractiveness[current] ^ (edge.second <= k ? edge.second : 0);
                q.push(neighbor);
            }
        }
    }
    return attractiveness[v];
}
int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        for (int i = 0; i < n - 1; i++) {
            int u, v, c;
            cin >> u >> v >> c;
            adj[u - 1].push_back({v - 1, c});
            adj[v - 1].push_back({u - 1, c});
        }
        int m;
        cin >> m;
        for (int i = 0; i < m; i++) {
            int u, v, k;
            cin >> u >> v >> k;
            cout << bfs(u - 1, v - 1, k) << endl;
        }
        for (int i = 0; i < n; i++) {
            adj[i].clear();
        }
    }
    return 0;
}

