import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    static final int MAXN = 100005;
    static int[][] adj = new int[MAXN][MAXN];
    static int[] visited = new int[MAXN];
    static int[] distance = new int[MAXN];
    static int[] attractiveness = new int[MAXN];
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            for (int i = 0; i < n - 1; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                int c = scanner.nextInt();
                adj[u][v] = c;
                adj[v][u] = c;
            }
            int m = scanner.nextInt();
            for (int i = 0; i < m; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                int k = scanner.nextInt();
                System.out.println(bfs(u, v, k));
            }
        }
    }
    public static int bfs(int u, int v, int k) {
        Queue<Integer> queue = new LinkedList<>();
        queue.add(u);
        visited[u] = 1;
        distance[u] = 0;
        attractiveness[u] = 0;
        while (!queue.isEmpty()) {
            int current = queue.poll();
            for (int i = 0; i < MAXN; i++) {
                if (adj[current][i] != 0 && !visited[i]) {
                    visited[i] = 1;
                    distance[i] = distance[current] + 1;
                    attractiveness[i] = attractiveness[current] ^ (adj[current][i] <= k ? adj[current][i] : 0);
                    queue.add(i);
                }
            }
        }
        return attractiveness[v];
    }
}

